import{j as l,b as i,c as e,aa as o}from"./chunks/framework.Bxf40uRC.js";const _=JSON.parse('{"title":"Linux常用指令","description":"","frontmatter":{},"headers":[],"relativePath":"Linux/linux常用指令.md","filePath":"Linux/linux常用指令.md","lastUpdated":null}'),t={name:"Linux/linux常用指令.md"},c=o('<h1 id="linux常用指令" tabindex="-1">Linux常用指令 <a class="header-anchor" href="#linux常用指令" aria-label="Permalink to &quot;Linux常用指令&quot;">​</a></h1><h2 id="网络监控" tabindex="-1">网络监控 <a class="header-anchor" href="#网络监控" aria-label="Permalink to &quot;网络监控&quot;">​</a></h2><ol><li><strong>netstat/ss -tunlp</strong> : t 表示tcp，u表示udp，l表示listen，n表示使用ip和端口展示，p展示pid</li><li><strong>iftop</strong>：监控网络带宽的使用情况</li><li><strong>ifconfig</strong>: 查看本地ip地址信息</li></ol><h2 id="系统管理" tabindex="-1">系统管理 <a class="header-anchor" href="#系统管理" aria-label="Permalink to &quot;系统管理&quot;">​</a></h2><ol><li><p><strong>top</strong> ：监控内存和cpu使用率的命令</p><ul><li>过程中按P代表按照CPU使用率降序排序</li><li>M代表按照Memory降序排序</li><li>按下1显示所有cpu的核心使用情况</li></ul></li><li><p><strong>free</strong>：命令用于显示系统的空闲、已用、交换空间等内存信息</p><ul><li><code>-b</code>：以字节为单位显示内存使用情况。</li><li><code>-k</code>：以KB为单位显示内存使用情况（这是默认设置）。</li><li><code>-m</code>：以MB为单位显示内存使用情况。</li><li><code>-g</code>：以GB为单位显示内存使用情况。</li><li><code>-h</code>：以人类可读的格式（自动选择适当的单位，例如KB、MB或GB）显示内存使用情况。</li><li><code>-t</code>：显示内存总计行（即总计物理内存+交换空间）。</li></ul></li><li><p><code>vmstat</code>（Virtual Memory Statistics）命令是Linux系统中用于显示关于虚拟内存、进程、CPU活动等信息的工具。它提供了系统的即时状态，包括内存使用、系统进程、中断、CPU活动和交换空间使用情况。<code>vmstat</code>可以帮助识别系统的性能瓶颈，特别是内存和CPU相关的问题。</p><ul><li>Procs（进程） <ul><li><code>r</code>：等待运行的进程数。</li><li><code>b</code>：处于不可中断睡眠状态的进程数。</li></ul></li><li>Memory（内存） <ul><li><code>swpd</code>：使用的交换空间大小。</li><li><code>free</code>：空闲的物理内存大小。</li><li><code>buff</code>：用作缓冲的内存大小。</li><li><code>cache</code>：用作缓存的内存大小。</li></ul></li><li>Swap（交换） <ul><li><code>si</code>：每秒从交换空间读入内存的数据量。</li><li><code>so</code>：每秒从内存写入交换空间的数据量。</li></ul></li><li>IO（输入/输出） <ul><li><code>bi</code>：每秒从块设备读入的数据量。</li><li><code>bo</code>：每秒向块设备写入的数据量。</li></ul></li><li>System（系统） <ul><li><code>in</code>：每秒的中断次数，包括时钟中断。</li><li><code>cs</code>：每秒的上下文切换次数。</li></ul></li><li>CPU（中央处理器） <ul><li><code>us</code>：用户模式下CPU的时间百分比。</li><li><code>sy</code>：系统（内核）模式下CPU的时间百分比。</li><li><code>id</code>：空闲CPU的时间百分比。</li><li><code>wa</code>：等待IO的CPU时间百分比。</li><li><code>st</code>：被偷走的时间百分比（对于虚拟机环境）。</li></ul></li><li>cat /proc/vmstat | grep &#39;pswpin|pswpout&#39; ：可以用来统计内存交换的次数</li></ul></li><li><p><strong>systemctl</strong>：控制systemd系统和服务管理器。</p><ul><li><p>启动服务：<code>systemctl start servicename</code></p></li><li><p>停止服务：<code>systemctl stop servicename</code></p></li><li><p>重启服务：<code>systemctl restart servicename</code></p></li><li><p>显示服务状态：<code>systemctl status servicename</code></p></li><li><p>开机自启：<code>systemctl enable servicename</code></p></li><li><p>禁止开机自启：<code>systemctl disable servicename</code></p></li></ul></li><li><p><strong>ps</strong>：显示当前所有的进程</p><ul><li>-e显示所有进程</li><li>-f表示全格式</li><li>a表示显示除控制进程（session leaders）和没有控制终端的进程外的所有进程</li><li>u表示用户为中心的格式输出，提供每个进程的用户名称，CPU和内存使用率等详细信息</li><li>x显示没有控制终端的进程，通常与进行一起使用</li></ul></li><li><p><strong>kill -9 pid</strong>: -9强制终止进程，不加的话就是终止进程</p></li><li><p><strong>killall</strong>：根据进程名终止所有进程</p></li><li><p><strong>jobs</strong>：列出当前会话中的所有任务，包括后台运行的进程。</p></li><li><p><strong>nice</strong>：优先级范围从-20（最高优先级）到19（最低优先级)</p><ul><li>nice -n 5 command：表示nice值 + 5启动command，通常越小，优先级越高</li></ul></li><li><p><strong>journalctl</strong> : 查看系统所有日志</p></li></ol><ul><li>-u 表示查看特定服务的日志</li><li>--since today 表示查看今天的日志</li><li>-f 滚动查看最新的日志</li><li>--since &quot;2021-01-30 14:00&quot; --until &quot;2021-01-30 16:00&quot; 查看某个时间段的日志</li></ul><ol start="11"><li><strong>lscpu</strong>：查看cpu信息</li><li><strong>getconf</strong>：可以获取系统变量的值 <ul><li>LONG_BIT：表示长整型的bit数目</li></ul></li></ol><h2 id="文件操作" tabindex="-1">文件操作 <a class="header-anchor" href="#文件操作" aria-label="Permalink to &quot;文件操作&quot;">​</a></h2><ol><li><strong>pwd</strong>：显示当前文件目录</li><li><strong>mv</strong>： 可以进行文件命名操作，也可以进行文件移动操作</li></ol>',9),s=[c];function n(d,a,r,u,p,m){return i(),e("div",null,s)}const h=l(t,[["render",n]]);export{_ as __pageData,h as default};
